const headers = $input.item.json.headers || {};
const query = $input.item.json.query || $input.item.json.queryParameters || {};
const auth = headers.authorization || headers.Authorization || '';
const token = auth.startsWith('Bearer ') ? auth.slice(7).trim() : auth.trim();
const debug = query.debug == '1' || query.debug === 'true';

if (!token && !debug) {
  return [{ json: { error: 'Token requerido', numbers: [] } }];
}

const GRAPH = 'https://graph.facebook.com/v25.0';

try {
  let wabas = [];
  const debug_info = { endpoints: [] };

  // Try direct /me/whatsapp_business_accounts
  try {
    const wabaData = await this.helpers.request({
      method: 'GET',
      url: GRAPH + '/me/whatsapp_business_accounts',
      qs: { fields: 'id,name', access_token: token },
      json: true
    });
    debug_info.endpoints.push({ endpoint: 'me/whatsapp_business_accounts', ok: true, data_count: Array.isArray(wabaData.data) ? wabaData.data.length : (wabaData ? 1 : 0) });
    if (wabaData && Array.isArray(wabaData.data) && wabaData.data.length) {
      wabas = wabaData.data;
    }
  } catch (e) { debug_info.endpoints.push({ endpoint: 'me/whatsapp_business_accounts', ok: false, error: e.message }); }

  // Fallback: list businesses and query each business for owned_whatsapp_business_accounts
  if (wabas.length === 0) {
    try {
      const bizData = await this.helpers.request({
        method: 'GET',
        url: GRAPH + '/me/businesses',
        qs: { access_token: token },
        json: true
      });
      debug_info.endpoints.push({ endpoint: 'me/businesses', ok: true, data_count: Array.isArray(bizData.data) ? bizData.data.length : 0 });
      if (bizData && Array.isArray(bizData.data)) {
        for (const biz of bizData.data) {
          try {
            const owned = await this.helpers.request({
              method: 'GET',
              url: GRAPH + '/' + biz.id + '/owned_whatsapp_business_accounts',
              qs: { fields: 'id,name', access_token: token },
              json: true
            });
            debug_info.endpoints.push({ endpoint: biz.id + '/owned_whatsapp_business_accounts', ok: true, data_count: Array.isArray(owned.data) ? owned.data.length : 0 });
            if (owned && Array.isArray(owned.data)) {
              for (const o of owned.data) wabas.push(o);
            }
          } catch (e) { debug_info.endpoints.push({ endpoint: biz.id + '/owned_whatsapp_business_accounts', ok: false, error: e.message }); }
        }
      }
    } catch (e) { debug_info.endpoints.push({ endpoint: 'me/businesses', ok: false, error: e.message }); }
  }

  const numbers = [];
  for (const waba of wabas) {
    try {
      const pnData = await this.helpers.request({
        method: 'GET',
        url: GRAPH + '/' + waba.id + '/phone_numbers',
        qs: { fields: 'id,display_phone_number,verified_name,quality_rating,platform_type', access_token: token },
        json: true
      });
      debug_info.endpoints.push({ endpoint: waba.id + '/phone_numbers', ok: true, data_count: Array.isArray(pnData.data) ? pnData.data.length : 0 });
      if (pnData && Array.isArray(pnData.data)) {
        for (const pn of pnData.data) {
          numbers.push({
            phone_number_id: pn.id,
            waba_id: waba.id,
            waba_name: waba.name || '',
            display_phone_number: pn.display_phone_number || '',
            verified_name: pn.verified_name || '',
            quality_rating: pn.quality_rating || '',
            platform_type: pn.platform_type || ''
          });
        }
      }
    } catch (e) { debug_info.endpoints.push({ endpoint: waba.id + '/phone_numbers', ok: false, error: e.message }); }
  }

  if (debug) {
    const tokenPreview = token ? (token.slice(0,6) + '...' + token.slice(-6)) : null;
    const wabaIds = wabas.map(w => w.id).slice(0,10);
    return [{ json: { debug: { auth_present: !!auth, token_preview: tokenPreview, wabas_count: wabas.length, waba_ids: wabaIds, numbers_count: numbers.length, endpoints: debug_info.endpoints }, numbers } }];
  }

  return [{ json: { numbers } }];
} catch (err) {
  return [{ json: { error: (err && err.message) ? err.message : 'Error Graph API', numbers: [] } }];
}
